```typescript
export interface Decider<C, E, S> {
  initialState: S;
  decide: (command: C, state: S) => E[];
  evolve: (state: S, event: E) => S;
}

export type ArtisanStudioState =
  | { status: "none" }
  | { status: "open"; id: string; owner: string; members: number }
  | { status: "closed"; id: string; closedAt: string };

export type ArtisanStudioCommand =
  | { type: "open"; id: string; owner: string }
  | { type: "admit"; member: string }
  | { type: "close"; closedAt: string };

export type ArtisanStudioEvent =
  | { type: "StudioOpened"; id: string; owner: string }
  | { type: "StudioMemberAdmitted"; member: string }
  | { type: "StudioClosed"; closedAt: string };

export class DomainError extends Error {}

export const initialState: ArtisanStudioState = { status: "none" };

export function decide(
  command: ArtisanStudioCommand,
  state: ArtisanStudioState,
): ArtisanStudioEvent[] {
  switch (command.type) {
    case "open":
      if (state.status === "open") throw new DomainError("already open");
      return [{ type: "StudioOpened", id: command.id, owner: command.owner }];
    case "admit":
      if (state.status !== "open") throw new DomainError("not open");
      return [{ type: "StudioMemberAdmitted", member: command.member }];
    case "close":
      if (state.status !== "open") throw new DomainError("cannot close");
      return [{ type: "StudioClosed", closedAt: command.closedAt }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

export function evolve(
  state: ArtisanStudioState,
  event: ArtisanStudioEvent,
): ArtisanStudioState {
  switch (event.type) {
    case "StudioOpened":
      return { status: "open", id: event.id, owner: event.owner, members: 0 };
    case "StudioMemberAdmitted":
      return state.status === "open"
        ? { ...state, members: state.members + 1 }
        : state;
    case "StudioClosed":
      return state.status === "open"
        ? { status: "closed", id: state.id, closedAt: event.closedAt }
        : state;
    default: {
      const _: never = event;
      return _;
    }
  }
}

export const artisanStudioDecider: Decider<
  ArtisanStudioCommand,
  ArtisanStudioEvent,
  ArtisanStudioState
> = { initialState, decide, evolve };
