```typescript
export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export type CraftCommissionState =
  | { status: "none" }
  | { status: "quoted"; id: string; price: number }
  | { status: "accepted"; id: string; price: number }
  | { status: "delivered"; id: string; deliveredAt: string };

export type CraftCommissionCommand =
  | { type: "quote"; id: string; price: number }
  | { type: "accept" }
  | { type: "deliver"; deliveredAt: string };

export type CraftCommissionEvent =
  | { type: "CommissionQuoted"; id: string; price: number }
  | { type: "CommissionAccepted" }
  | { type: "CommissionDelivered"; deliveredAt: string };

export class CommissionError extends Error {}

const initialState: CraftCommissionState = { status: "none" };

function decide(
  c: CraftCommissionCommand,
  s: CraftCommissionState,
): CraftCommissionEvent[] {
  switch (c.type) {
    case "quote":
      if (s.status !== "none") throw new CommissionError("already quoted");
      return [{ type: "CommissionQuoted", id: c.id, price: c.price }];
    case "accept":
      if (s.status !== "quoted") throw new CommissionError("no quote");
      return [{ type: "CommissionAccepted" }];
    case "deliver":
      if (s.status !== "accepted") throw new CommissionError("not accepted");
      return [{ type: "CommissionDelivered", deliveredAt: c.deliveredAt }];
    default: {
      const _: never = c;
      return _;
    }
  }
}

function evolve(
  s: CraftCommissionState,
  e: CraftCommissionEvent,
): CraftCommissionState {
  switch (e.type) {
    case "CommissionQuoted":
      return { status: "quoted", id: e.id, price: e.price };
    case "CommissionAccepted":
      return s.status === "quoted"
        ? { status: "accepted", id: s.id, price: s.price }
        : s;
    case "CommissionDelivered":
      return s.status === "accepted"
        ? { status: "delivered", id: s.id, deliveredAt: e.deliveredAt }
        : s;
    default: {
      const _: never = e;
      return _;
    }
  }
}

export const craftCommissionDecider: Decider<
  CraftCommissionCommand,
  CraftCommissionEvent,
  CraftCommissionState
> = { initialState, decide, evolve };
