```typescript
export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export type GlazeTestState =
  | { status: "pending"; id: string }
  | { status: "running"; id: string; started: string }
  | { status: "complete"; id: string; score: number };

export type GlazeTestCommand =
  | { type: "register"; id: string }
  | { type: "start"; started: string }
  | { type: "record"; score: number };

export type GlazeTestEvent =
  | { type: "GlazeTestRegistered"; id: string }
  | { type: "GlazeTestStarted"; started: string }
  | { type: "GlazeTestScored"; score: number };

export class GlazeError extends Error {}

const initialState: GlazeTestState = { status: "pending", id: "" };

function decide(c: GlazeTestCommand, s: GlazeTestState): GlazeTestEvent[] {
  switch (c.type) {
    case "register":
      if (s.id !== "") throw new GlazeError("already registered");
      return [{ type: "GlazeTestRegistered", id: c.id }];
    case "start":
      if (s.status !== "pending") throw new GlazeError("cannot start");
      return [{ type: "GlazeTestStarted", started: c.started }];
    case "record":
      if (s.status === "complete") throw new GlazeError("already complete");
      if (s.status !== "running") throw new GlazeError("not running");
      return [{ type: "GlazeTestScored", score: c.score }];
    default: {
      const _: never = c;
      return _;
    }
  }
}

function evolve(s: GlazeTestState, e: GlazeTestEvent): GlazeTestState {
  switch (e.type) {
    case "GlazeTestRegistered":
      return { status: "pending", id: e.id };
    case "GlazeTestStarted":
      return s.status === "pending"
        ? { status: "running", id: s.id, started: e.started }
        : s;
    case "GlazeTestScored":
      return s.status === "running"
        ? { status: "complete", id: s.id, score: e.score }
        : s;
    default: {
      const _: never = e;
      return _;
    }
  }
}

export const glazeTestDecider: Decider<
  GlazeTestCommand,
  GlazeTestEvent,
  GlazeTestState
> = { initialState, decide, evolve };
