export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export type ExhibitionPieceState =
  | { status: "none" }
  | { status: "submitted"; id: string; artist: string }
  | { status: "accepted"; id: string; artist: string }
  | { status: "displayed"; id: string; slot: string }
  | { status: "retired"; id: string };

export type ExhibitionPieceCommand =
  | { type: "submit"; id: string; artist: string }
  | { type: "accept" }
  | { type: "display"; slot: string }
  | { type: "retire" };

export type ExhibitionPieceEvent =
  | { type: "PieceSubmitted"; id: string; artist: string }
  | { type: "PieceAccepted" }
  | { type: "PieceDisplayed"; slot: string }
  | { type: "PieceRetired" };

export class ExhibitionError extends Error {}

const initialState: ExhibitionPieceState = { status: "none" };

function decide(
  c: ExhibitionPieceCommand,
  s: ExhibitionPieceState,
): ExhibitionPieceEvent[] {
  switch (c.type) {
    case "submit":
      if (s.status !== "none") throw new ExhibitionError("already submitted");
      return [{ type: "PieceSubmitted", id: c.id, artist: c.artist }];
    case "accept":
      if (s.status !== "submitted") throw new ExhibitionError("no submission");
      return [{ type: "PieceAccepted" }];
    case "display":
      if (s.status !== "accepted") throw new ExhibitionError("not accepted");
      return [{ type: "PieceDisplayed", slot: c.slot }];
    case "retire":
      if (s.status === "retired" || s.status === "none")
        throw new ExhibitionError("cannot retire");
      return [{ type: "PieceRetired" }];
    default: {
      const _: never = c;
      return _;
    }
  }
}

function evolve(
  s: ExhibitionPieceState,
  e: ExhibitionPieceEvent,
): ExhibitionPieceState {
  switch (e.type) {
    case "PieceSubmitted":
      return { status: "submitted", id: e.id, artist: e.artist };
    case "PieceAccepted":
      return s.status === "submitted"
        ? { status: "accepted", id: s.id, artist: s.artist }
        : s;
    case "PieceDisplayed":
      return s.status === "accepted"
        ? { status: "displayed", id: s.id, slot: e.slot }
        : s;
    case "PieceRetired":
      return s.status === "none"
        ? s
        : { status: "retired", id: "id" in s ? s.id : "" };
    default: {
      const _: never = e;
      return _;
    }
  }
}

export const exhibitionPieceDecider: Decider<
  ExhibitionPieceCommand,
  ExhibitionPieceEvent,
  ExhibitionPieceState
> = { initialState, decide, evolve };
