```typescript
export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export type SupplyRestockState =
  | { status: "none" }
  | { status: "scheduled"; id: string; item: string; qty: number }
  | { status: "complete"; id: string }
  | { status: "cancelled"; id: string };

export type SupplyRestockCommand =
  | { type: "schedule"; id: string; item: string; qty: number }
  | { type: "complete" }
  | { type: "cancel"; reason: string };

export type SupplyRestockEvent =
  | { type: "RestockScheduled"; id: string; item: string; qty: number }
  | { type: "RestockCompleted" }
  | { type: "RestockCancelled"; reason: string };

export class RestockError extends Error {}

const initialState: SupplyRestockState = { status: "none" };

function decide(
  c: SupplyRestockCommand,
  s: SupplyRestockState,
): SupplyRestockEvent[] {
  switch (c.type) {
    case "schedule":
      if (s.status !== "none") throw new RestockError("already scheduled");
      return [
        { type: "RestockScheduled", id: c.id, item: c.item, qty: c.qty },
      ];
    case "complete":
      if (s.status !== "scheduled") throw new RestockError("cannot complete");
      return [{ type: "RestockCompleted" }];
    case "cancel":
      if (s.status !== "scheduled")
        throw new RestockError("cannot cancel");
      return [{ type: "RestockCancelled", reason: c.reason }];
    default: {
      const _: never = c;
      return _;
    }
  }
}

function evolve(
  s: SupplyRestockState,
  e: SupplyRestockEvent,
): SupplyRestockState {
  switch (e.type) {
    case "RestockScheduled":
      return { status: "scheduled", id: e.id, item: e.item, qty: e.qty };
    case "RestockCompleted":
      return s.status === "scheduled" ? { status: "complete", id: s.id } : s;
    case "RestockCancelled":
      return s.status === "scheduled"
        ? { status: "cancelled", id: s.id }
        : s;
    default: {
      const _: never = e;
      return _;
    }
  }
}

export const supplyRestockDecider: Decider<
  SupplyRestockCommand,
  SupplyRestockEvent,
  SupplyRestockState
> = { initialState, decide, evolve };
```

```typescript
export type ArtistCollectiveEvent =
  | { type: "CollectiveFormed"; id: string; name: string }
  | { type: "ArtistJoined"; artist: string }
  | { type: "ArtistLeft"; artist: string }
  | { type: "CollectiveRenamed"; name: string }
  | { type: "CollectiveDisbanded" };

export interface RosterView {
  id: string;
  name: string;
  members: string[];
  disbanded: boolean;
}

export const emptyView: RosterView = {
  id: "",
  name: "",
  members: [],
  disbanded: false,
};

export function project(
  view: RosterView,
  event: ArtistCollectiveEvent,
): RosterView {
  switch (event.type) {
    case "CollectiveFormed":
      return { ...view, id: event.id, name: event.name };
    case "ArtistJoined":
      return view.members.includes(event.artist)
        ? view
        : { ...view, members: [...view.members, event.artist] };
    case "ArtistLeft":
      return { ...view, members: view.members.filter((m) => m !== event.artist) };
    case "CollectiveRenamed":
      return { ...view, name: event.name };
    case "CollectiveDisbanded":
      return { ...view, disbanded: true };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export function buildRoster(events: ArtistCollectiveEvent[]): RosterView {
  return events.reduce(project, emptyView);
}
```

