    case "EntryRegistered":
      return { ...view, id: event.id, booth: event.booth, status: "pending" };
    case "EntryApproved":
      return { ...view, status: "approved" };
    case "EntryRejected":
      return { ...view, status: "rejected", reason: event.reason };
    case "BoothReassigned":
      return { ...view, booth: event.booth };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export function foldDirectory(events: TradeShowEntryEvent[]): DirectoryView {
  return events.reduce(project, emptyView);
}
