export type MarketStallEvent =
  | { type: "StallOpened"; id: string; day: string }
  | { type: "SaleRecorded"; amount: number }
  | { type: "RefundIssued"; amount: number }
  | { type: "StallClosed" };

export interface SalesView {
  id: string;
  day: string;
  gross: number;
  refunds: number;
  closed: boolean;
