```typescript
export const CURRENT_VERSION = 3 as const;

export interface CurrentState {
  id: string;
  founder: string;
  memberCount: number;
}

export interface Snapshot<S> {
  version: number;
  state: S;
}

interface V1 {
  id: string;
  owner: string;
}
interface V2 {
  id: string;
  owner: string;
  memberCount: number;
}

function v1Tov2(state: V1): V2 {
  return { ...state, memberCount: 0 };
}

function v2Tov3(state: V2): CurrentState {
  return { id: state.id, founder: state.owner, memberCount: state.memberCount };
}

export function upgradeSnapshot(
  snap: Snapshot<unknown>,
): Snapshot<CurrentState> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) {
    state = v1Tov2(state as V1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as V2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new Error(`unknown snapshot version ${version}`);
  }
  return { version: CURRENT_VERSION, state: state as CurrentState };
}
