export const CURRENT_VERSION = 3 as const;

export interface CurrentState {
  id: string;
  peakTemp: number;
  profile: string;
}

export interface Snapshot<S> {
  version: number;
  state: S;
}

interface V1 {
  id: string;
  temp: number;
}
interface V2 {
  id: string;
  temp: number;
  profile: string;
}

function v1Tov2(s: V1): V2 {
  return { ...s, profile: "default" };
}

function v2Tov3(s: V2): CurrentState {
  return { id: s.id, peakTemp: s.temp, profile: s.profile };
}

export function upgradeSnapshot(
  snap: Snapshot<unknown>,
): Snapshot<CurrentState> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) {
    state = v1Tov2(state as V1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as V2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new Error(`snapshot version ${version} not supported`);
  }
  return { version: CURRENT_VERSION, state: state as CurrentState };
}
