export type ExhibitionPieceEvent =
  | { type: "PieceSubmitted"; id: string }
  | { type: "PieceAccepted"; id: string }
  | { type: "PieceDisplayed"; id: string; slot: string };

export interface StoredEvent {
  revision: bigint;
  event: ExhibitionPieceEvent;
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventStoreSubscription {
  readFrom(from: bigint | null): AsyncIterable<StoredEvent>;
}

export type View = Record<string, { status: string; slot?: string }>;

export function project(view: View, event: ExhibitionPieceEvent): View {
  switch (event.type) {
    case "PieceSubmitted":
      return { ...view, [event.id]: { status: "submitted" } };
    case "PieceAccepted":
      return { ...view, [event.id]: { ...view[event.id], status: "accepted" } };
    case "PieceDisplayed":
      return {
        ...view,
        [event.id]: { status: "displayed", slot: event.slot },
      };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function runSubscription(
  name: string,
  store: EventStoreSubscription,
  checkpoints: CheckpointStore,
  persistView: (v: View) => Promise<void>,
): Promise<void> {
  const start = await checkpoints.read(name);
  let view: View = {};
  for await (const se of store.readFrom(start)) {
    view = project(view, se.event);
    await persistView(view);
    await checkpoints.write(name, se.revision);
  }
}
