export type ArtistCollectiveEvent =
  | { type: "CollectiveFormed"; id: string; name: string }
  | { type: "ArtistJoined"; id: string; artist: string };

export interface StoredEvent {
  position: bigint;
  event: ArtistCollectiveEvent;
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface Subscription {
  from(position: bigint | null): AsyncIterable<StoredEvent>;
}

interface RosterRow {
  id: string;
  name: string;
  members: string[];
}
type Roster = Record<string, RosterRow>;

function project(view: Roster, event: ArtistCollectiveEvent): Roster {
  switch (event.type) {
    case "CollectiveFormed":
      return { ...view, [event.id]: { id: event.id, name: event.name, members: [] } };
    case "ArtistJoined": {
      const row = view[event.id];
      if (!row) return view;
      return {
        ...view,
        [event.id]: { ...row, members: [...row.members, event.artist] },
      };
    }
    default: {
      const _: never = event;
      return _;
    }
  }
}

