  name: string,
  sub: Subscription,
  checkpoints: CheckpointStore,
  save: (view: Roster) => Promise<void>,
): Promise<void> {
  const from = await checkpoints.read(name);
  let roster: Roster = {};
  for await (const se of sub.from(from)) {
    roster = project(roster, se.event);
    await save(roster);
    await checkpoints.write(name, se.position);
  }
