import { Effect } from "effect";

export type MarketStallEvent =
  | { type: "StallOpened"; id: string }
  | { type: "SaleRecorded"; id: string; amount: number };

export interface StoredEvent {
  position: bigint;
  event: MarketStallEvent;
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface Subscription {
  from(pos: bigint | null): AsyncIterable<StoredEvent>;
}

interface SalesRow {
  id: string;
  gross: number;
}
type SalesView = Record<string, SalesRow>;

function project(view: SalesView, event: MarketStallEvent): SalesView {
  switch (event.type) {
    case "StallOpened":
      return { ...view, [event.id]: { id: event.id, gross: 0 } };
    case "SaleRecorded": {
      const row = view[event.id];
      if (!row) return view;
      return { ...view, [event.id]: { ...row, gross: row.gross + event.amount } };
    }
    default: {
      const _: never = event;
      return _;
    }
  }
}

export const runSubscription = (
  name: string,
  sub: Subscription,
  checkpoints: CheckpointStore,
  persist: (v: SalesView) => Promise<void>,
): Effect.Effect<void, Error> =>
  Effect.gen(function* () {
    const start = yield* Effect.tryPromise({
      try: () => checkpoints.read(name),
      catch: (e) => new Error(String(e)),
    });
    let view: SalesView = {};
    let position = start;
    const iter = sub.from(start);
    const run = async (): Promise<bigint | null> => {
      for await (const se of iter) {
        view = project(view, se.event);
        await persist(view);
        await checkpoints.write(name, se.position);
        position = se.position;
      }
      return position;
    };
    yield* Effect.tryPromise({
      try: run,
      catch: (e) => new Error(String(e)),
    });
  });
