export function when(
  state: KilnFiringState,
  event: KilnFiringEvent,
): KilnFiringState {
  switch (event.type) {
    case "FiringScheduled":
      return { id: event.id, temp: event.temp, status: "scheduled" };
    case "FiringIgnited":
      return { ...state, status: "firing" };
    case "FiringCompleted":
      return { ...state, status: "complete" };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  fold: (state: S, event: E) => S,
  seed: S,
): Promise<S> {
  let state = seed;
  for await (const event of stream) {
    state = fold(state, event);
  }
  return state;
}

export async function foldKilnFiring(
  stream: AsyncIterable<KilnFiringEvent>,
): Promise<KilnFiringState> {
  return aggregateStream<KilnFiringState, KilnFiringEvent>(stream, when, initial);
