export class UnknownEventError extends Error {}

export type CurrentEvent =
  | { type: "StudioOpened"; version: 3; id: string; founder: string }
  | { type: "StudioClosed"; version: 1; closedAt: string };

interface RawStudioOpenedV1 {
  type: "StudioOpened";
  version: 1;
  id: string;
}
interface RawStudioOpenedV2 {
  type: "StudioOpened";
  version: 2;
  id: string;
  owner: string;
}
interface RawStudioOpenedV3 {
  type: "StudioOpened";
  version: 3;
  id: string;
  founder: string;
}
interface RawStudioClosedV1 {
  type: "StudioClosed";
  version: 1;
  closedAt: string;
}

type Raw =
  | RawStudioOpenedV1
  | RawStudioOpenedV2
  | RawStudioOpenedV3
  | RawStudioClosedV1;

export function upcast(raw: unknown): CurrentEvent {
  const r = raw as Raw;
  switch (r.type) {
    case "StudioOpened":
      if (r.version === 1) {
        return { type: "StudioOpened", version: 3, id: r.id, founder: "unknown" };
      }
      if (r.version === 2) {
        return { type: "StudioOpened", version: 3, id: r.id, founder: r.owner };
      }
      return r;
    case "StudioClosed":
      return r;
    default:
      throw new UnknownEventError(JSON.stringify(raw));
  }
}

export interface EventStore {
  readStream(stream: string): Promise<unknown[]>;
}

export async function loadUpcasted(
  store: EventStore,
  stream: string,
): Promise<CurrentEvent[]> {
  const raw = await store.readStream(stream);
  return raw.map(upcast);
}
