export type ArtistCollectiveEvent =
  | { type: "CollectiveFormed"; id: string; name: string }
  | { type: "ArtistJoined"; id: string; artist: string };

export interface StoredEvent {
  revision: bigint;
  event: ArtistCollectiveEvent;
}

interface RosterRow {
  id: string;
  name: string;
  members: string[];
}
export type RosterView = Record<string, RosterRow>;

export function project(view: RosterView, event: ArtistCollectiveEvent): RosterView {
  switch (event.type) {
    case "CollectiveFormed":
      return { ...view, [event.id]: { id: event.id, name: event.name, members: [] } };
    case "ArtistJoined": {
      const row = view[event.id];
      if (!row) return view;
      return { ...view, [event.id]: { ...row, members: [...row.members, event.artist] } };
    }
    default: {
      const _: never = event;
      return _;
    }
  }
}

export interface EventStoreReader {
  readBatch(from: bigint, batchSize: number): Promise<StoredEvent[]>;
}

export interface RebuildOpts {
  from: bigint;
  batchSize: number;
  store: EventStoreReader;
  persist: (view: RosterView, cursor: bigint) => Promise<void>;
}

export async function rebuild(opts: RebuildOpts): Promise<void> {
  let cursor = opts.from;
  let view: RosterView = {};
  for (;;) {
    const batch = await opts.store.readBatch(cursor, opts.batchSize);
    if (batch.length === 0) return;
    for (const se of batch) {
      view = project(view, se.event);
      cursor = se.revision + 1n;
    }
    await opts.persist(view, cursor);
  }
}
