```typescript
export type SagaEvent =
  | { type: "PieceSubmitted"; id: string; artist: string }
  | { type: "ReviewPassed"; id: string }
  | { type: "ReviewFailed"; id: string; reason: string }
  | { type: "PieceAccepted"; id: string };

export type SagaCommand =
  | { type: "ScheduleReview"; id: string; artist: string }
  | { type: "AcceptPiece"; id: string }
  | { type: "RejectPiece"; id: string; reason: string };

export function react(event: SagaEvent): SagaCommand | null {
  switch (event.type) {
    case "PieceSubmitted":
      return { type: "ScheduleReview", id: event.id, artist: event.artist };
    case "ReviewPassed":
      return { type: "AcceptPiece", id: event.id };
    case "ReviewFailed":
      return { type: "RejectPiece", id: event.id, reason: event.reason };
    case "PieceAccepted":
      return null;
    default: {
      const _: never = event;
      return _;
    }
  }
}

export interface CommandBus {
  appendToStream(stream: string, commands: SagaCommand[]): Promise<void>;
}

export async function drive(
  bus: CommandBus,
  stream: string,
  event: SagaEvent,
): Promise<void> {
  const cmd = react(event);
  if (cmd === null) return;
  await bus.appendToStream(stream, [cmd]);
}
