```typescript
export type ArtistCollectiveEvent =
  | { type: "CollectiveFormed"; id: string; name: string }
  | { type: "ArtistJoined"; id: string; artist: string }
  | { type: "CollectiveDisbanded"; id: string };

export type IntegrationEvent =
  | {
      schema: "collective.v1.formed";
      payload: { id: string; name: string };
    }
  | {
      schema: "collective.v1.member_joined";
      payload: { collectiveId: string; artist: string };
    };

export function translate(
  event: ArtistCollectiveEvent,
): IntegrationEvent | null {
  switch (event.type) {
    case "CollectiveFormed":
      return {
        schema: "collective.v1.formed",
        payload: { id: event.id, name: event.name },
      };
    case "ArtistJoined":
      return {
        schema: "collective.v1.member_joined",
        payload: { collectiveId: event.id, artist: event.artist },
      };
    case "CollectiveDisbanded":
      return null;
    default: {
      const _: never = event;
      return _;
    }
  }
}

export interface OutboxStore {
  appendToStream(topic: string, events: IntegrationEvent[]): Promise<void>;
}

export async function publish(
  outbox: OutboxStore,
  topic: string,
  domainEvents: ArtistCollectiveEvent[],
): Promise<void> {
  const integrationEvents: IntegrationEvent[] = [];
  for (const ev of domainEvents) {
    const mapped = translate(ev);
    if (mapped !== null) integrationEvents.push(mapped);
  }
  if (integrationEvents.length > 0) {
    await outbox.appendToStream(topic, integrationEvents);
  }
}
```

```typescript
export type SupplyRestockEvent =
  | { type: "RestockScheduled"; id: string; item: string; qty: number }
  | { type: "RestockCompleted"; id: string };

export interface OutboxRow {
  id: string;
  payload: Record<string, unknown>;
  publishedAt: string | null;
}

export interface Transaction {
  insertOutbox(row: OutboxRow): Promise<void>;
  appendToStream(
    stream: string,
    events: SupplyRestockEvent[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
  commit(): Promise<void>;
  rollback(): Promise<void>;
}

export interface Connection {
  begin(): Promise<Transaction>;
}

// A separate publisher worker polls outbox rows where publishedAt is null,
// delivers them to the bus, and marks them published. Not implemented here.
export async function appendWithOutbox(
  stream: string,
  events: SupplyRestockEvent[],
  outboxRows: OutboxRow[],
  expectedRevision: bigint | "no_stream" | "any",
  conn: Connection,
): Promise<void> {
  const tx = await conn.begin();
  try {
    for (const row of outboxRows) {
      await tx.insertOutbox(row);
    }
    await tx.appendToStream(stream, events, { expectedRevision });
    await tx.commit();
  } catch (err) {
    await tx.rollback();
    throw err;
  }
}
