```typescript
import { Effect } from "effect";

export type KilnFiringEvent =
  | { type: "FiringScheduled"; id: string; temp: number }
  | { type: "FiringIgnited" }
  | { type: "FiringCompleted" };

export interface KilnFiringState {
  id: string;
  temp: number;
  status: "scheduled" | "firing" | "complete" | "none";
}

const initial: KilnFiringState = { id: "", temp: 0, status: "none" };

function evolve(
  s: KilnFiringState,
  e: KilnFiringEvent,
): KilnFiringState {
  switch (e.type) {
    case "FiringScheduled":
      return { id: e.id, temp: e.temp, status: "scheduled" };
    case "FiringIgnited":
      return { ...s, status: "firing" };
    case "FiringCompleted":
      return { ...s, status: "complete" };
    default: {
      const _: never = e;
      return _;
    }
  }
}

export interface EventStore {
  readStream(stream: string): Promise<KilnFiringEvent[]>;
}

export const loadKilnFiring = (
  store: EventStore,
  stream: string,
): Effect.Effect<KilnFiringState, Error> =>
  Effect.gen(function* () {
    const events = yield* Effect.tryPromise({
      try: () => store.readStream(stream),
      catch: (e) => new Error(String(e)),
    });
    return events.reduce(evolve, initial);
  });
