```typescript
export interface GlazeTestEvent {
  type: string;
  data: Record<string, unknown>;
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  appendToStream(
    stream: string,
    events: GlazeTestEvent[],
    options: { expectedRevision: ExpectedRevision },
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(stream: string) {
    super(`concurrency conflict on ${stream}`);
  }
}

export async function save(
  store: EventStore,
  stream: string,
  events: GlazeTestEvent[],
  expectedRevision: ExpectedRevision,
): Promise<bigint> {
  try {
    const { nextExpectedRevision } = await store.appendToStream(
      stream,
      events,
      { expectedRevision },
    );
    return nextExpectedRevision;
  } catch (err) {
    if (
      err instanceof Error &&
      /wrong.*(expected|revision|version)/i.test(err.message)
    ) {
      throw new ConcurrencyConflict(stream);
    }
    throw err;
  }
}
