```typescript
export type MentorshipSessionEvent =
  | { type: "SessionBooked"; id: string; mentor: string; mentee: string }
  | { type: "SessionStarted"; at: string }
  | { type: "SessionCompleted"; rating: number };

export type MentorshipSessionState =
  | { status: "idle" }
  | {
      status: "booked";
      id: string;
      mentor: string;
      mentee: string;
    }
  | {
      status: "running";
      id: string;
      startedAt: string;
    }
  | {
      status: "complete";
      id: string;
      rating: number;
    };

const initial: MentorshipSessionState = { status: "idle" };

export function evolve(
  s: MentorshipSessionState,
  e: MentorshipSessionEvent,
): MentorshipSessionState {
  switch (e.type) {
    case "SessionBooked":
      return {
        status: "booked",
        id: e.id,
        mentor: e.mentor,
        mentee: e.mentee,
      };
    case "SessionStarted":
      return s.status === "booked"
        ? { status: "running", id: s.id, startedAt: e.at }
        : s;
    case "SessionCompleted":
      return s.status === "running"
        ? { status: "complete", id: s.id, rating: e.rating }
        : s;
    default: {
      const _: never = e;
      return _;
    }
  }
}

export function aggregate(
  events: MentorshipSessionEvent[],
): MentorshipSessionState {
  return events.reduce(evolve, initial);
}
```
